const __pageData = JSON.parse('{"title":"所有关系，“见面成本”就是试金石","description":"","frontmatter":{"title":"所有关系，“见面成本”就是试金石","date":"2026-02-14T15:20","layout":"post"},"headers":[],"relativePath":"posts/cost-of-meeting.md","filePath":"posts/cost-of-meeting.md","lastUpdated":1772603207000}');
